decimal avgLiveWeightRatio = 0;
decimal avgRatio = 0;
decimal avgCounterMinusPluck  = 0;
decimal netBirdTotalReport  = 0;
decimal chickRehangReport = 0;
decimal result = 0;
decimal TotalDressedWeightReport = 0;
private void xrTableCell33_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal liveWeight = 0;
decimal counterTotal = 0;
decimal doa = 0;
decimal culls = 0;

// --- Read values ---
if (GetCurrentColumnValue("LiveWeight") != null)
    liveWeight = Convert.ToDecimal(GetCurrentColumnValue("LiveWeight"));

if (GetCurrentColumnValue("CounterTotal") != null)
    counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal"));

if (GetCurrentColumnValue("DOA") != null)
    doa = Convert.ToDecimal(GetCurrentColumnValue("DOA"));

if (GetCurrentColumnValue("Culls") != null)
    culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

// --- Equation ---
decimal denominator = counterTotal + doa + culls;
decimal result = 0;
if (denominator > 0)
    result = liveWeight / denominator;

    avgLiveWeightRatio += result;
// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##"); // format with up to 2 decimals

}

private void xrTableCell22_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
          xrTableCell22.Text = avgLiveWeightRatio.ToString("0");
          avgLiveWeightRatio = 0; // reset for next LineType group

}

private void xrTableCell13_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal liveWeight = 0;
decimal counterTotal = 0;
decimal doa = 0;
decimal culls = 0;

// --- Read values ---
if (GetCurrentColumnValue("LiveWeight") != null)
    liveWeight = Convert.ToDecimal(GetCurrentColumnValue("LiveWeight"));

if (GetCurrentColumnValue("CounterTotal") != null)
    counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal"));

if (GetCurrentColumnValue("DOA") != null)
    doa = Convert.ToDecimal(GetCurrentColumnValue("DOA"));

if (GetCurrentColumnValue("Culls") != null)
    culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

// --- Equation ---
decimal denominator = counterTotal + doa + culls;
decimal ratio = 0;

if (denominator > 0)
    ratio = liveWeight / denominator;

// --- Add to report totals (for average) ---
decimal ratioReportSum = 0;
int ratioReportCount = 0;
ratioReportSum += ratio;     // keep sum of ratios
ratioReportCount++;          // count how many ratios added

// --- Compute running average ---
if (ratioReportCount > 0)
    avgRatio = ratioReportSum / ratioReportCount;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = ratio.ToString("0.##"); // format with up to 2 decimals

}

private void xrTableCell23_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
           xrTableCell23.Text = avgRatio.ToString("0");
           avgRatio= 0; // reset for next LineType group


}

private void xrTableCell16_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal counterTotal = 0;
decimal pluckReject = 0;

// --- Read values ---
if (GetCurrentColumnValue("CounterTotal") != null)
    counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal"));

if (GetCurrentColumnValue("PluckReject") != null)
    pluckReject = Convert.ToDecimal(GetCurrentColumnValue("PluckReject"));

// --- Equation ---
decimal result = counterTotal - pluckReject;
        avgCounterMinusPluck += result ;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##"); // format with up to 2 decimals

}

private void xrTableCell29_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
          xrTableCell29.Text = avgCounterMinusPluck.ToString("0");
          avgCounterMinusPluck = 0; // reset for next LineType group

}


private void xrTable2_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
   // --- Declare values ---
decimal netBirdTotal = 0;
decimal chickRehang = 0;

// --- Read values ---
if (GetCurrentColumnValue("NetBirdTotaal") != null)
    netBirdTotal = Convert.ToDecimal(GetCurrentColumnValue("NetBirdTotaal"));
    netBirdTotalReport += netBirdTotal;
if (GetCurrentColumnValue("ChickRehang") != null)
    chickRehang = Convert.ToDecimal(GetCurrentColumnValue("ChickRehang"));
    chickRehangReport += chickRehang;

// --- Equation ---
result = chickRehangReport + netBirdTotalReport ;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##"); // format with up to 2 decimals

}

private void xrTableCell37_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
                // --- Declare values ---
decimal totalDressedWeight = 0;

if (GetCurrentColumnValue("TotalDressedWeight") != null)
    totalDressedWeight = Convert.ToDecimal(GetCurrentColumnValue("TotalDressedWeight"));

// --- Keep running sum for Avg ---
decimal dressedWeightSum = 0;
int dressedWeightCount = 0;

dressedWeightSum += totalDressedWeight;
dressedWeightCount++;

// --- Compute average ---
decimal avgDressedWeight = 0;
if (dressedWeightCount > 0)
    avgDressedWeight = dressedWeightSum / dressedWeightCount;

// --- Equation ---
decimal TotalDressedWeightReport = result * avgDressedWeight;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = TotalDressedWeightReport.ToString("0.##"); // format with up to 2 decimals

}
